let state = $state({ open: false, pinned: false });
let closeTimer;
const sidebar = {
  get open() {
    return state.open;
  },
  enter() {
    clearTimeout(closeTimer);
    state.open = true;
  },
  leave() {
    clearTimeout(closeTimer);
    if (state.pinned) return;
    closeTimer = setTimeout(() => state.open = false, 120);
  },
  pin() {
    clearTimeout(closeTimer);
    state.pinned = true;
    state.open = true;
  },
  unpin() {
    state.pinned = false;
    this.leave();
  }
};
export {
  sidebar
};
